module synchronous_counter(
    input clk,
    input enable,
    input clear,
    output reg [3:0] count
);
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk) begin
        if (clear)
            count <= 0;
        else if (enable)
            count <= count + 1;
    end

endmodule
